module top_module(countdown, all_tiles_counted, clock, reset, enable);output reg [3:0] countdown;
	output all_tiles_counted;

	input clock, reset, enable;

	always @(posedge clock, posedge reset)
		begin
			if (reset)
				begin
					countdown <= 0;
				end

			else if (enable)
				if (countdown == 4'd10)
						countdown <= 0;
				else
						countdown <= countdown + 4'd1;
		end

	assign all_tiles_counted = (countdown == 0) ? 1'd1 : 1'd0;endmodule
